1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  previousContracts: number;
4	};
5	
6	export type Item = {
7	  type: string;
8	};
9	
10	const PROCESSING_FEE = 5;
11	
12	export function quote(customer: Customer, items: Item[]): number {
13	  if (items.length === 0) return PROCESSING_FEE;
14	  return 110 + PROCESSING_FEE;
15	}
